import React, { useEffect, useState } from 'react';
import { Table, TableBody, TableCell, TableHead, TableRow, Button, TextField, Box, Typography, CircularProgress } from '@material-ui/core';
import { getExpenses, createExpense } from '../services/ApiService';
import { makeStyles } from '@material-ui/core/styles';

const useStyles = makeStyles((theme) => ({
  root: {
    padding: theme.spacing(3),
  },
  form: {
    display: 'flex',
    gap: theme.spacing(2),
    marginBottom: theme.spacing(2),
  },
}));

export default function ExpenseManagement() {
  const classes = useStyles();
  const [expenses, setExpenses] = useState([]);
  const [newExpense, setNewExpense] = useState({ description: '', amount: 0 });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    setLoading(true);
    getExpenses().then(res => {
      if (res.error) {
        setError('Failed to load expenses');
      } else {
        setExpenses(res.data);
      }
      setLoading(false);
    });
  }, []);

  const addExpense = () => {
    createExpense(newExpense).then(res => {
      if (!res.error) {
        setExpenses([...expenses, res.data]);
        setNewExpense({ description: '', amount: 0 });
      } else {
        setError('Failed to create expense');
      }
    });
  };

  if (loading) return <CircularProgress />;
  if (error) return <Typography color="error">{error}</Typography>;

  return (
    <div className={classes.root}>
      <Typography variant="h4" gutterBottom>Expense Management</Typography>
      <Box className={classes.form}>
        <TextField
          label="Description"
          value={newExpense.description}
          onChange={e => setNewExpense({ ...newExpense, description: e.target.value })}
        />
        <TextField
          label="Amount"
          type="number"
          value={newExpense.amount}
          onChange={e => setNewExpense({ ...newExpense, amount: parseFloat(e.target.value) })}
        />
        <Button onClick={addExpense} color="primary" variant="contained">Add Expense</Button>
      </Box>
      <Table>
        <TableHead>
          <TableRow>
            <TableCell>Description</TableCell>
            <TableCell>Amount</TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {expenses.map(expense => (
            <TableRow key={expense.id}>
              <TableCell>{expense.description}</TableCell>
              <TableCell>{expense.amount}</TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  );
}
